const norm = s => (s || '').toString().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/\b(sa|sas|sarl|sasu|eurl|group|groupe|holding|france|se)\b/g, ' ').replace(/[^a-z0-9]+/g, ' ').replace(/\s+/g, ' ').trim();
const cibles = $input.all().map(it => it.json);
const contacts = $('Airtable : Contacts').all().map(it => it.json);
const companies = $('Airtable : Companies').all().map(it => it.json);
const compNames = new Set(companies.map(c => norm(c['Company Name'])).filter(Boolean));
const cibleNames = new Set(cibles.map(c => norm(c['Entreprise'])).filter(Boolean));
const BLOCK = new Set(['entreprise', 'independant', 'etudiant']);
const isJunk = (n) => !n || n.length < 2 || BLOCK.has(n) || /freelance|auto entrepreneur|recherche d emploi|jardin|portee mondial/.test(n);
const seen = new Set(); const out = [];
for (const ct of contacts) {
  const ent = ct['Entreprise']; const co2 = ct['Companies 2'];
  const hasLink = (Array.isArray(ent) && ent.length) || (Array.isArray(co2) && co2.length);
  if (hasLink) continue;
  const emp = (ct['Company Name'] || '').toString().trim();
  if (!emp) continue;
  const n = norm(emp);
  if (compNames.has(n)) continue;
  if (seen.has(n)) continue; seen.add(n);
  let statut = 'A INCUBER';
  if (isJunk(n)) statut = 'SUSPECT (exclure ?)';
  else if (cibleNames.has(n)) statut = 'DEJA en Cibles (skip)';
  out.push({ json: { employeur: emp, statut } });
}
out.sort((a, b) => (a.json.statut > b.json.statut ? 1 : -1));
const nInc = out.filter(o => o.json.statut === 'A INCUBER').length;
const nSus = out.filter(o => o.json.statut.startsWith('SUSPECT')).length;
const nDup = out.filter(o => o.json.statut.startsWith('DEJA')).length;
out.unshift({ json: { employeur: '=== ' + out.length + ' employeurs C2 distincts ===', statut: nInc + ' a incuber / ' + nSus + ' suspects / ' + nDup + ' deja en cibles' } });
return out;
